239â†’/// Why a branch was selected as a GA target.
240â†’#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
241â†’#[serde(rename_all = "snake_case")]
242â†’pub enum TargetReason {
243â†’    /// Branch was never discovered by any method.
244â†’    Uncovered,
245â†’    /// Branch was observed but its constraint is Unknown (opaque to solver).
246â†’    OpaqueConstraint,
247â†’}
248â†’
249â†’/// A branch that the Genetic Algorithm should target for coverage.
250â†’#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
251â†’pub struct TargetBranch {
252â†’    /// Unique branch identifier within the function.
253â†’    pub branch_id: u32,
254â†’    /// Source line number of the branch.
255â†’    pub line: u32,
256â†’    /// Why this branch is targeted.
257â†’    pub reason: TargetReason,
258â†’    /// Hint about the constraint to guide mutation strategy.
259â†’    pub constraint_hint: Option<String>,
260â†’}
261â†’
262â†’/// Extract unsolved branch targets from a random exploration result.
263â†’///
264â†’/// Compares the static branch list from `analysis` against branches discovered
265â†’/// during exploration to identify targets the GA should focus on.
266â†’pub fn extract_targets(
267â†’    analysis: &FunctionAnalysis,
268â†’    result: &ObservationOutput,
269â†’) -> Vec<TargetBranch> {
270â†’    extract_targets_inner(&analysis.branches, &result.discoveries, &result.raw_results)
271â†’}
272â†’
273â†’/// Extract unsolved branch targets from a concolic exploration result.
274â†’///
275â†’/// Same logic as [`extract_targets`] but accepts the orchestrator's result type.
276â†’pub fn extract_targets_concolic(
277â†’    analysis: &FunctionAnalysis,
278â†’    result: &ExploreResult,
279â†’) -> Vec<TargetBranch> {
280â†’    extract_targets_inner(&analysis.branches, &result.discoveries, &result.raw_results)
281â†’}
282â†’
283â†’/// Core target extraction logic operating on slices.
284â†’///
285â†’/// A branch is targeted if:
286â†’/// - It was never discovered (not in `discoveries`) â†’ `TargetReason::Uncovered`
287â†’/// - It was discovered but its runtime constraint is `Unknown` â†’ `TargetReason::OpaqueConstraint`
288â†’fn extract_targets_inner(
289â†’    branches: &[BranchInfo],
290â†’    discoveries: &[(u32, DiscoveryMethod)],
291â†’    raw_results: &[(Vec<serde_json::Value>, ExecuteResult)],
292â†’) -> Vec<TargetBranch> {
293â†’    let discovered: HashSet<u32> = discoveries.iter().map(|(id, _)| *id).collect();
294â†’
295â†’    // Collect opaque constraint hints from runtime branch decisions.
296â†’    let mut opaque_hints: HashMap<u32, String> = HashMap::new();
297â†’    for (_, exec) in raw_results {
298â†’        for decision in &exec.branch_path {
299â†’            if let SymConstraint::Unknown { hint } = &decision.constraint {
300â†’                opaque_hints
301â†’                    .entry(decision.branch_id)
302â†’                    .or_insert_with(|| hint.clone());
303â†’            }
304â†’        }
305â†’    }
306â†’
307â†’    let mut targets: Vec<TargetBranch> = Vec::new();
308â†’    for branch in branches {
309â†’        if !discovered.contains(&branch.id) {
310â†’            targets.push(TargetBranch {
311â†’                branch_id: branch.id,
312â†’                line: branch.line,
313â†’                reason: TargetReason::Uncovered,
314â†’                constraint_hint: if branch.condition_text.is_empty() {
315â†’                    None
316â†’                } else {
317â†’                    Some(branch.condition_text.clone())
318â†’                },
319â†’            });
320â†’        } else if let Some(hint) = opaque_hints.get(&branch.id) {
321â†’            targets.push(TargetBranch {
322â†’                branch_id: branch.id,
323â†’                line: branch.line,
324â†’                reason: TargetReason::OpaqueConstraint,
325â†’                constraint_hint: if hint.is_empty() { None } else { Some(hint.clone()) },
326â†’            });
327â†’        }
328â†’    }
329â†’
330â†’    targets.sort_by_key(|t| t.branch_id);
331â†’    targets
332â†’}
