 44â†’/// Aggregated results of analyzing all discovered source files.
 45â†’#[derive(Debug, Clone)]
 46â†’pub struct FunctionRegistry {
 47â†’    /// All function entries, keyed by a qualified identifier (file_path::function_name).
 48â†’    entries: Vec<FunctionEntry>,
 49â†’    /// Index from qualified name to position in entries vec.
 50â†’    index: HashMap<String, usize>,
