 69â†’        self.entries.is_empty()
 70â†’    }
 71â†’
 72â†’    /// Iterate over all function entries.
 73â†’    pub fn entries(&self) -> &[FunctionEntry] {
 74â†’        &self.entries
 75â†’    }
 76â†’
 77â†’    /// Look up a function by its qualified name (file_path::function_name).
 78â†’    pub fn get(&self, qualified_name: &str) -> Option<&FunctionEntry> {
 79â†’        self.index.get(qualified_name).map(|&i| &self.entries[i])
 80â†’    }
 81â†’
 82â†’    /// Get all functions from a specific file.
