 92â†’        self.entries.iter().filter(|e| e.exported).collect()
 93â†’    }
 94â†’
 95â†’    /// Build a qualified name for a function in a file.
 96â†’    pub fn qualified_name(file_path: &Path, function_name: &str) -> String {
 97â†’        format!("{}::{}", file_path.display(), function_name)
 98â†’    }
