 80â†’/// Configuration for a concolic exploration session.
 81â†’#[derive(Debug, Clone)]
 82â†’pub struct ExploreConfig {
 83â†’    /// Maximum number of unique paths to explore before stopping.
 84â†’    pub max_iterations: usize,
 85â†’    /// Maximum total executions (including duplicated paths) before stopping.
 86â†’    pub max_executions: usize,
 87â†’    /// Stop after this many consecutive executions without discovering a new path.
 88â†’    /// Set to 0 to disable plateau detection.
 89â†’    pub plateau_threshold: usize,
 90â†’    /// Mock configurations to pass through to Execute commands.
 91â†’    pub mocks: Vec<crate::protocol::MockConfig>,
 92â†’    /// Z3 solver timeout in milliseconds per query. None means no limit.
 93â†’    pub solver_timeout_ms: Option<u64>,
 94â†’    /// Per-function exploration wall-clock timeout. Whichever of this or
 95â†’    /// `max_iterations`/`max_executions` triggers first stops the loop.
 96â†’    pub timeout_explore: Option<Duration>,
 97â†’}
