  2â†’//!
  3â†’//! Provides a static set of known edge-case values (e.g., `i32::MAX`, empty
  4â†’//! string, `NaN`) that improve branch coverage for common boundary checks.
  5â†’//! These are used as low-priority seed inputs during exploration, after solver
  6â†’//! and user-provided values.
  7â†’
  8â†’use serde::{Deserialize, Serialize};
  9â†’use serde_json::{json, Value};
 10â†’
 11â†’use crate::types::TypeInfo;
 12â†’
 13â†’/// Why a boundary value is interesting.
 14â†’#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
 15â†’#[serde(rename_all = "snake_case")]
 16â†’pub enum BoundaryCategory {
 17â†’    /// Classic boundary: zero, min, max, off-by-one.
 18â†’    Boundary,
 19â†’    /// Security-relevant: null bytes, injection patterns.
 20â†’    Security,
 21â†’    /// Unicode edge cases: emoji, RTL, BOM, combining characters.
 22â†’    Unicode,
 23â†’    /// Floating-point precision traps.
 24â†’    Precision,
 25â†’    /// Empty / absent values.
 26â†’    Empty,
 27â†’    /// Overflow / underflow triggers.
 28â†’    Overflow,
 29â†’}
 30â†’
 31â†’/// A single boundary value with metadata.
 32â†’#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 33â†’pub struct BoundaryEntry {
 34â†’    /// The JSON-encoded boundary value.
 35â†’    pub value: Value,
 36â†’    /// Why this value is interesting.
 37â†’    pub category: BoundaryCategory,
 38â†’    /// Human-readable description.
 39â†’    pub description: String,
 40â†’}
 41â†’
 42â†’impl BoundaryEntry {
 43â†’    fn new(value: Value, category: BoundaryCategory, description: &str) -> Self {
 44â†’        Self {
 45â†’            value,
 46â†’            category,
 47â†’            description: description.to_string(),
 48â†’        }
 49â†’    }
 50â†’}
 51â†’
 52â†’/// Returns boundary values applicable to the given type.
 53â†’#[must_use]
 54â†’pub fn get_boundary_values(type_info: &TypeInfo) -> Vec<BoundaryEntry> {
 55â†’    match type_info {
 56â†’        TypeInfo::Int => int_boundaries(),
 57â†’        TypeInfo::Float => float_boundaries(),
 58â†’        TypeInfo::Str => string_boundaries(),
 59â†’        TypeInfo::Bool => bool_boundaries(),
 60â†’        TypeInfo::Array { .. } => array_boundaries(),
 61â†’        TypeInfo::Object { .. } => object_boundaries(),
 62â†’        TypeInfo::Nullable { inner } => {
 63â†’            let mut entries = vec![BoundaryEntry::new(
 64â†’                Value::Null,
 65â†’                BoundaryCategory::Empty,
 66â†’                "null value",
 67â†’            )];
 68â†’            entries.extend(get_boundary_values(inner));
 69â†’            entries
 70â†’        }
 71â†’        TypeInfo::Union { variants } => {
 72â†’            let mut entries = Vec::new();
 73â†’            for variant in variants {
 74â†’                entries.extend(get_boundary_values(variant));
 75â†’            }
 76â†’            entries
 77â†’        }
 78â†’        TypeInfo::Complex { .. } | TypeInfo::Opaque { .. } | TypeInfo::Unknown => Vec::new(),
 79â†’    }
 80â†’}
 81â†’
 82â†’/// Returns boundary values for a specific category only.
 83â†’#[must_use]
 84â†’pub fn get_boundary_values_for_category(
 85â†’    type_info: &TypeInfo,
 86â†’    category: BoundaryCategory,
 87â†’) -> Vec<BoundaryEntry> {
 88â†’    get_boundary_values(type_info)
 89â†’        .into_iter()
 90â†’        .filter(|e| e.category == category)
 91â†’        .collect()
 92â†’}
