629â†’                        mocks: config.mocks.clone(),
630â†’                        setup_context: setup_context.clone(),
631â†’                    })
632â†’                    .await?;
633â†’
634â†’                if let (
635â†’                    ResponseResult::Execute(float_result),
636â†’                    ResponseResult::Execute(floor_result),
637â†’                ) = (&float_resp.result, &floor_resp.result) {
638â†’                    total_probes += 1;
639â†’
640â†’                    let fhash = path_hash(float_result, &config.loop_buckets);
641â†’                    let flhash = path_hash(floor_result, &config.loop_buckets);
642â†’                    seen_paths.insert(fhash);
643â†’                    seen_paths.insert(flhash);
644â†’                    for &line in &float_result.lines_executed {
645â†’                        all_lines.insert(line);
646â†’                    }
647â†’                    for &line in &floor_result.lines_executed {
648â†’                        all_lines.insert(line);
649â†’                    }
650â†’
651â†’                    if crate::float_probe::executions_agree(float_result, floor_result) {
652â†’                        agreements += 1;
653â†’                    } else if let Some(v) = float_inputs.get(idx).and_then(|v| v.as_f64()) {
654â†’                        divergent_values.push(v);
655â†’                    }
656â†’
657â†’                    raw_results.push((float_inputs.clone(), (**float_result).clone()));
658â†’                }
659â†’            }
660â†’
661â†’            let classification = crate::float_probe::classify(
662â†’                agreements,
663â†’                total_probes,
664â†’                crate::float_probe::AGREEMENT_THRESHOLD,
665â†’            );
666â†’            float_probe_results.push(crate::float_probe::FloatProbeResult {
667â†’                param_index: idx,
668â†’                param_name: analysis.params[idx].name.clone(),
669â†’                classification,
670â†’                agreements,
671â†’                total_probes,
672â†’                divergent_values,
673â†’            });
674â†’        }
675â†’    }
676â†’
677â†’    let float_bias = crate::float_probe::build_bias_map(&float_probe_results);
678â†’    let has_integer_treating = float_bias
679â†’        .values()
680â†’        .any(|c| *c == crate::float_probe::FloatClassification::IntegerTreating);
681â†’
682â†’    // --- User-provided candidate inputs (highest priority, no budget cap) ---
683â†’    let mut user_iter = config.user_seeds.iter().cloned().peekable();
684â†’
685â†’    // --- Literal-derived seed inputs ---
686â†’    // Execute extracted literals first to cover magic-value branches before random exploration.
687â†’    let literal_candidates = literals_to_candidate_inputs(&analysis.params, &analysis.literals);
688â†’    let literal_budget = literal_candidates
689â†’        .len()
690â†’        .min(config.max_iterations as usize / 2);
691â†’    let mut literal_iter = literal_candidates.into_iter().take(literal_budget).peekable();
692â†’
693â†’    // --- Candidate inputs (from --inputs or .shatter/ config) ---
694â†’    // Priority above pool seeds, below literal seeds.
695â†’    let candidate_budget = config
696â†’        .candidate_inputs
697â†’        .len()
698â†’        .min(config.max_iterations as usize / 3);
699â†’    let mut candidate_iter = config.candidate_inputs.iter().take(candidate_budget).cloned().peekable();

150â†’    }
151â†’}
