216â†’/// Compute a hash of the branch path (branch_id + taken pairs) to identify unique paths.
217â†’pub fn hash_branch_path(branch_path: &[crate::execution_record::BranchDecision]) -> u64 {
218â†’    let mut hasher = std::hash::DefaultHasher::new();
219â†’    for decision in branch_path {
220â†’        decision.branch_id.hash(&mut hasher);
221â†’        decision.taken.hash(&mut hasher);
222â†’    }
223â†’    hasher.finish()
224â†’}
