226â†’/// Extract the list of solvable `SymExpr` path conditions from an execution result's branch path.
227â†’///
228â†’/// Each constraint is adjusted based on the `taken` field so that negating it
229â†’/// in the solver produces inputs that flip the branch:
230â†’/// - `taken=true`: the path condition is the constraint itself
231â†’/// - `taken=false`: the path condition is `NOT(constraint)`, because the branch
232â†’///   condition evaluated to false
233â†’///
234â†’/// Returns `None` for branches with `Unknown` constraints; those are skipped
235â†’/// by the solver but may be targeted by fuzzing.
236â†’fn extract_sym_constraints(result: &ExecuteResult) -> Vec<Option<SymExpr>> {
237â†’    result
238â†’        .branch_path
239â†’        .iter()
240â†’        .map(|decision| match &decision.constraint {
241â†’            SymConstraint::Expr { expr } => {
242â†’                if decision.taken {
243â†’                    Some(expr.clone())
244â†’                } else {
245â†’                    // The branch was not taken, so the actual path condition
246â†’                    // is NOT(constraint). Wrapping it here ensures that when
247â†’                    // the solver negates this entry, it produces the raw
248â†’                    // constraint â€” i.e., the condition needed to take the branch.
249â†’                    Some(SymExpr::UnOp {
250â†’                        op: crate::sym_expr::UnOpKind::Not,
251â†’                        operand: Box::new(expr.clone()),
252â†’                    })
253â†’                }
254â†’            }
255â†’            SymConstraint::Unknown { .. } => None,
256â†’        })
257â†’        .collect()
258â†’}
