686â†’/// Simple input fuzzing: produce a handful of variations on the base inputs.
687â†’///
688â†’/// For each JSON value in the input list, generate mutations:
689â†’/// - Numbers: Â±1, Ã—-1, 0, boundary values
690â†’/// - Booleans: flip
691â†’/// - Strings: empty string, "a"
692â†’pub(crate) fn fuzz_inputs(base: &[serde_json::Value]) -> Vec<Vec<serde_json::Value>> {
693â†’    let mut results = Vec::new();
694â†’
695â†’    for (idx, val) in base.iter().enumerate() {
696â†’        let mutations = fuzz_single_value(val);
697â†’        for mutated in mutations {
698â†’            let mut new_inputs = base.to_vec();
699â†’            new_inputs[idx] = mutated;
700â†’            results.push(new_inputs);
701â†’        }
702â†’    }
703â†’
704â†’    results
705â†’}
706â†’
707â†’pub(crate) fn fuzz_single_value(val: &serde_json::Value) -> Vec<serde_json::Value> {
708â†’    match val {
709â†’        serde_json::Value::Number(n) => {
710â†’            let mut mutations = Vec::new();
711â†’            if let Some(i) = n.as_i64() {
712â†’                let candidates = [i + 1, i - 1, 0, -i];
713â†’                for c in candidates {
714â†’                    let json_val = serde_json::json!(c);
715â†’                    if c != i && !mutations.contains(&json_val) {
716â†’                        mutations.push(json_val);
717â†’                    }
718â†’                }
719â†’            } else if let Some(f) = n.as_f64() {
720â†’                let candidates = [f + 1.0, f - 1.0, 0.0];
721â†’                for c in candidates {
722â†’                    let json_val = serde_json::json!(c);
723â†’                    if (c - f).abs() > f64::EPSILON && !mutations.contains(&json_val) {
724â†’                        mutations.push(json_val);
725â†’                    }
726â†’                }
727â†’            }
728â†’            mutations
729â†’        }
730â†’        serde_json::Value::Bool(b) => vec![serde_json::json!(!b)],
731â†’        serde_json::Value::String(_) => {
732â†’            vec![serde_json::json!(""), serde_json::json!("a")]
733â†’        }
734â†’        _ => vec![],
735â†’    }
736â†’}
