  1â†’//! Frontier tracking for concolic exploration.
  2â†’//!
  3â†’//! A frontier represents a branch reached but not fully explored during
  4â†’//! concolic execution. Each frontier tracks which parameters block progress
  5â†’//! and how many consecutive attempts have failed to make progress (stall count).
  6â†’//! The `FrontierSet` maintains a collection of frontiers per function,
  7â†’//! serving them in priority order: lower depth first, then lower stall count.
  8â†’
  9â†’use serde::{Deserialize, Serialize};
 10â†’
 11â†’/// Stall count threshold after which a frontier is considered deeply stalled.
 12â†’/// Consumers can use this to deprioritize or abandon frontiers that aren't
 13â†’/// making progress despite repeated attempts.
 14â†’pub const DEFAULT_MAX_STALL: u32 = 10;
 15â†’
 16â†’/// A single exploration frontier â€” a branch reached but not yet solved.
 17â†’///
 18â†’/// `blocking_params` lists the parameter indices (into the function's `ParamInfo`
 19â†’/// vec) that appear in the branch's symbolic constraint, identified via
 20â†’/// `sym_expr::extract_param_names`. `best_prefix` holds the input vector from
 21â†’/// the execution that reached this branch deepest.
 22â†’#[derive(Debug, Clone, Serialize, Deserialize)]
 23â†’pub struct Frontier {
 24â†’    /// Branch identifier, unique within the function scope.
 25â†’    pub branch_id: u32,
 26â†’    /// Nesting depth of this branch in the control-flow graph (0 = top-level).
 27â†’    pub depth: u32,
 28â†’    /// Indices of parameters that influence this branch's condition.
 29â†’    pub blocking_params: Vec<usize>,
 30â†’    /// Input vector from the best execution reaching this branch.
 31â†’    pub best_prefix: Vec<serde_json::Value>,
 32â†’    /// Consecutive failed attempts to solve past this branch.
 33â†’    pub stall_count: u32,
 34â†’}
 35â†’
 36â†’/// Priority-ordered collection of frontiers for a single function.
 37â†’///
 38â†’/// Frontiers are served lowest-depth first (shallowest branches are explored
 39â†’/// before deeper ones), with stall count as a tiebreaker (less-stalled
 40â†’/// frontiers are preferred). The set is typically small (< 100 entries),
 41â†’/// so linear scans are acceptable.
 42â†’#[derive(Debug, Clone, Default)]
 43â†’pub struct FrontierSet {
 44â†’    frontiers: Vec<Frontier>,
 45â†’}
 46â†’
 47â†’impl FrontierSet {
 48â†’    pub fn new() -> Self {
 49â†’        Self::default()
 50â†’    }
 51â†’
 52â†’    /// Insert a frontier. If a frontier with the same `branch_id` already
 53â†’    /// exists, it is replaced.
 54â†’    pub fn insert(&mut self, frontier: Frontier) {
 55â†’        self.remove(frontier.branch_id);
 56â†’        self.frontiers.push(frontier);
 57â†’    }
 58â†’
 59â†’    /// Remove and return the highest-priority frontier (lowest depth, then
 60â†’    /// lowest stall count).
 61â†’    pub fn pop_highest_priority(&mut self) -> Option<Frontier> {
 62â†’        if self.frontiers.is_empty() {
 63â†’            return None;
 64â†’        }
 65â†’        let idx = self.best_index();
 66â†’        Some(self.frontiers.swap_remove(idx))
 67â†’    }
 68â†’
 69â†’    /// View the highest-priority frontier without removing it.
 70â†’    pub fn peek(&self) -> Option<&Frontier> {
 71â†’        if self.frontiers.is_empty() {
 72â†’            return None;
 73â†’        }
 74â†’        let idx = self.best_index();
 75â†’        Some(&self.frontiers[idx])
 76â†’    }
 77â†’
 78â†’    /// Increment the stall count for the frontier with the given `branch_id`.
 79â†’    /// Returns `true` if the frontier was found and updated.
 80â†’    pub fn increment_stall(&mut self, branch_id: u32) -> bool {
 81â†’        if let Some(f) = self.frontiers.iter_mut().find(|f| f.branch_id == branch_id) {
 82â†’            f.stall_count = f.stall_count.saturating_add(1);
 83â†’            true
 84â†’        } else {
 85â†’            false
 86â†’        }
 87â†’    }
 88â†’
 89â†’    /// Remove the frontier with the given `branch_id` (e.g., after solving it).
 90â†’    /// Returns the removed frontier, if any.
 91â†’    pub fn remove(&mut self, branch_id: u32) -> Option<Frontier> {
 92â†’        if let Some(pos) = self.frontiers.iter().position(|f| f.branch_id == branch_id) {
 93â†’            Some(self.frontiers.swap_remove(pos))
 94â†’        } else {
 95â†’            None
 96â†’        }
 97â†’    }
 98â†’
 99â†’    pub fn len(&self) -> usize {
100â†’        self.frontiers.len()
101â†’    }
102â†’
103â†’    pub fn is_empty(&self) -> bool {
104â†’        self.frontiers.is_empty()
105â†’    }
106â†’
107â†’    /// Iterate over all frontiers in arbitrary order.
108â†’    pub fn iter(&self) -> impl Iterator<Item = &Frontier> {
109â†’        self.frontiers.iter()
110â†’    }
111â†’
112â†’    /// Index of the highest-priority frontier.
113â†’    /// Caller must ensure `self.frontiers` is non-empty.
114â†’    fn best_index(&self) -> usize {
115â†’        self.frontiers
116â†’            .iter()
117â†’            .enumerate()
118â†’            .min_by(|(_, a), (_, b)| frontier_priority(a, b))
119â†’            .map(|(i, _)| i)
120â†’            .expect("best_index called on non-empty FrontierSet")
121â†’    }
122â†’}
123â†’
124â†’/// Compare two frontiers for priority ordering.
125â†’/// Lower depth wins; ties broken by lower stall count.
126â†’fn frontier_priority(a: &Frontier, b: &Frontier) -> std::cmp::Ordering {
127â†’    a.depth.cmp(&b.depth).then(a.stall_count.cmp(&b.stall_count))
128â†’}
129â†’
