131â†’mod tests {
132â†’    use super::*;
133â†’
134â†’    fn make_frontier(branch_id: u32, depth: u32, stall_count: u32) -> Frontier {
135â†’        Frontier {
136â†’            branch_id,
137â†’            depth,
138â†’            blocking_params: vec![],
139â†’            best_prefix: vec![],
140â†’            stall_count,
141â†’        }
142â†’    }
143â†’
144â†’    #[test]
145â†’    fn empty_set_returns_none() {
146â†’        let mut set = FrontierSet::new();
147â†’        assert!(set.is_empty());
148â†’        assert_eq!(set.len(), 0);
149â†’        assert!(set.peek().is_none());
150â†’        assert!(set.pop_highest_priority().is_none());

150â†’    /// Per-branch discovery attribution: which branch_id was first found by which method.
151â†’    pub discoveries: Vec<(u32, DiscoveryMethod)>,
152â†’    /// Fields detected as nondeterministic via within-run re-execution sampling.
153â†’    #[serde(default)]
154â†’    pub nondeterministic_fields: Vec<crate::nondeterminism::NondeterministicField>,
155â†’    /// Float probe results classifying Float params as integer-treating or float-sensitive.
156â†’    #[serde(default)]
157â†’    pub float_probe_results: Vec<crate::float_probe::FloatProbeResult>,
158â†’}
159â†’
160â†’/// Transitional alias: existing code that references `ExplorationResult`
161â†’/// continues to compile while consumers migrate to `ObservationOutput`.
162â†’pub type ExplorationResult = ObservationOutput;
163â†’
164â†’/// Type alias for pipeline composability. `ObserveResult` is the output of
165â†’/// the Observe stage (random exploration).
166â†’pub type ObserveResult = ObservationOutput;
167â†’
168â†’/// Errors that can occur during exploration.
169â†’#[derive(Debug, thiserror::Error)]
170â†’pub enum ExploreError {
171â†’    #[error("frontend error: {0}")]
172â†’    Frontend(#[from] FrontendError),
173â†’    #[error("unexpected response from frontend: {0}")]
174â†’    UnexpectedResponse(String),
175â†’}
