  1â†’//! Concolic execution loop: worklist-driven path exploration with Z3 solving.
  2â†’//!
  3â†’//! The orchestrator drives the concolic testing cycle:
  4â†’//! 1. Seed the worklist with initial inputs
  5â†’//! 2. Execute a function concretely via a frontend subprocess
  6â†’//! 3. Collect branch constraints from the execution trace
  7â†’//! 4. Negate each branch constraint and solve with Z3 for new inputs
  8â†’//! 5. Add solved inputs to the worklist; repeat until done
  9â†’//!
 10â†’//! Inputs from Z3 are prioritized over fuzzed or seed inputs so that the
 11â†’//! solver-guided exploration is always tried first.
 12â†’
 13â†’use contracts::requires;
 14â†’use std::collections::{BinaryHeap, HashSet};
 15â†’use std::hash::{Hash, Hasher};
 16â†’use std::time::{Duration, Instant};
 17â†’
 18â†’use rand::SeedableRng;
 19â†’use rand::rngs::StdRng;
 20â†’
 21â†’use crate::coverage_metrics::DiscoveryMethod;
 22â†’use crate::drilling;
 23â†’use crate::execution_record::SymConstraint;
 24â†’use crate::frontier::{Frontier, FrontierSet};
 25â†’use crate::frontend::{Frontend, FrontendError};
 26â†’use crate::protocol::{Command, ExecuteResult, ResponseResult};
 27â†’use crate::solver::{self, ConcreteValue, SolveResult};
 28â†’use crate::sym_expr::SymExpr;
 29â†’use crate::triage::{TriageState, TriageVerdict};
 30â†’use crate::types::{ComplexKind, ParamInfo};
 31â†’
 32â†’/// Parsed frontend capabilities from the handshake response.
 33â†’///
 34â†’/// During handshake, frontends declare which commands they support and which
 35â†’/// complex types they can reconstruct. The core uses this to avoid generating
 36â†’/// complex-typed inputs the frontend can't handle.
 37â†’#[derive(Debug, Clone, Default)]
 38â†’pub struct FrontendCapabilities {
 39â†’    /// Standard commands the frontend supports ("analyze", "execute", etc.).
 40â†’    pub commands: HashSet<String>,
 41â†’    /// Complex types the frontend can reconstruct from `__complex_type` JSON.
 42â†’    pub complex_types: HashSet<ComplexKind>,
 43â†’}
 44â†’
 45â†’impl FrontendCapabilities {
 46â†’    /// Parse raw capability strings from a handshake response.
 47â†’    ///
 48â†’    /// Strings prefixed with `"complex_type:"` are parsed as `ComplexKind` values.
 49â†’    /// All other strings are treated as command capabilities.
 50â†’    /// Unknown complex type names are silently ignored.
 51â†’    pub fn from_raw(capabilities: &[String]) -> Self {
 52â†’        let mut commands = HashSet::new();
 53â†’        let mut complex_types = HashSet::new();
 54â†’        for cap in capabilities {
 55â†’            if let Some(kind_str) = cap.strip_prefix("complex_type:") {
 56â†’                // ComplexKind uses serde rename_all = "snake_case", so we
 57â†’                // deserialize the bare string as a JSON string value.
 58â†’                if let Ok(kind) = serde_json::from_value::<ComplexKind>(
 59â†’                    serde_json::Value::String(kind_str.to_string()),
 60â†’                ) {
 61â†’                    complex_types.insert(kind);
 62â†’                }
 63â†’                // Silently ignore unknown complex type names
 64â†’            } else {
 65â†’                commands.insert(cap.clone());
 66â†’            }
 67â†’        }
 68â†’        Self {
 69â†’            commands,
 70â†’            complex_types,
 71â†’        }
 72â†’    }
 73â†’
 74â†’    /// Check whether the frontend declared support for a specific complex type.
 75â†’    pub fn supports_complex(&self, kind: ComplexKind) -> bool {
 76â†’        self.complex_types.contains(&kind)
 77â†’    }
 78â†’}
 79â†’
 80â†’/// Configuration for a concolic exploration session.
 81â†’#[derive(Debug, Clone)]
 82â†’pub struct ExploreConfig {
 83â†’    /// Maximum number of unique paths to explore before stopping.
 84â†’    pub max_iterations: usize,
 85â†’    /// Maximum total executions (including duplicated paths) before stopping.
 86â†’    pub max_executions: usize,
 87â†’    /// Stop after this many consecutive executions without discovering a new path.
 88â†’    /// Set to 0 to disable plateau detection.
 89â†’    pub plateau_threshold: usize,
 90â†’    /// Mock configurations to pass through to Execute commands.
 91â†’    pub mocks: Vec<crate::protocol::MockConfig>,
 92â†’    /// Z3 solver timeout in milliseconds per query. None means no limit.
 93â†’    pub solver_timeout_ms: Option<u64>,
 94â†’    /// Per-function exploration wall-clock timeout. Whichever of this or
 95â†’    /// `max_iterations`/`max_executions` triggers first stops the loop.
 96â†’    pub timeout_explore: Option<Duration>,
 97â†’}
 98â†’
 99â†’/// Default maximum total executions before stopping exploration.
100â†’pub const DEFAULT_MAX_EXECUTIONS: usize = 500;
101â†’
102â†’impl Default for ExploreConfig {
103â†’    fn default() -> Self {
104â†’        Self {
105â†’            max_iterations: 100,
106â†’            max_executions: DEFAULT_MAX_EXECUTIONS,
107â†’            plateau_threshold: 20,
108â†’            mocks: vec![],
109â†’            solver_timeout_ms: None,
110â†’            timeout_explore: None,
111â†’        }
112â†’    }
113â†’}
114â†’
115â†’/// How an input was generated â€” determines worklist priority.
116â†’#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
117â†’pub enum InputSource {
118â†’    /// Least priority: initial seed values.
119â†’    Seed = 0,
120â†’    /// Low priority: fuzzed from concrete values of unknown constraints.
121â†’    Fuzzed = 1,
122â†’    /// Medium priority: targeted mutation of blocking params on a stalled frontier.
123â†’    Drilled = 2,
124â†’    /// High priority: Z3-solved inputs targeting a specific branch.
125â†’    Z3Solved = 3,
126â†’    /// Highest priority: user-provided candidate inputs from `.shatter/` config.
127â†’    UserProvided = 4,
128â†’}
129â†’
130â†’/// An entry in the exploration worklist.
131â†’#[derive(Debug, Clone)]
132â†’pub struct WorklistEntry {
133â†’    /// Input values to pass to the function.
134â†’    pub inputs: Vec<serde_json::Value>,
135â†’    /// How these inputs were generated.
136â†’    pub source: InputSource,
137â†’}
138â†’
139â†’impl Eq for WorklistEntry {}
140â†’
141â†’impl PartialEq for WorklistEntry {
142â†’    fn eq(&self, other: &Self) -> bool {
143â†’        self.source == other.source
144â†’    }
145â†’}
146â†’
147â†’impl PartialOrd for WorklistEntry {
148â†’    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
149â†’        Some(self.cmp(other))
150â†’    }

