 51â†’    pub fn from_raw(capabilities: &[String]) -> Self {
 52â†’        let mut commands = HashSet::new();
 53â†’        let mut complex_types = HashSet::new();
 54â†’        for cap in capabilities {
 55â†’            if let Some(kind_str) = cap.strip_prefix("complex_type:") {
 56â†’                // ComplexKind uses serde rename_all = "snake_case", so we
 57â†’                // deserialize the bare string as a JSON string value.
 58â†’                if let Ok(kind) = serde_json::from_value::<ComplexKind>(
 59â†’                    serde_json::Value::String(kind_str.to_string()),
 60â†’                ) {
 61â†’                    complex_types.insert(kind);
 62â†’                }
 63â†’                // Silently ignore unknown complex type names
 64â†’            } else {
 65â†’                commands.insert(cap.clone());
 66â†’            }
 67â†’        }
 68â†’        Self {
 69â†’            commands,
 70â†’            complex_types,
 71â†’        }
 72â†’    }
 73â†’
 74â†’    /// Check whether the frontend declared support for a specific complex type.
 75â†’    pub fn supports_complex(&self, kind: ComplexKind) -> bool {
 76â†’        self.complex_types.contains(&kind)
 77â†’    }
 78â†’}
