388â†’/// Confidence-scored label for error intent classification.
389â†’#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
390â†’pub struct ErrorIntentLabel {
391â†’    /// "likely_validation", "likely_runtime", or "unknown"
392â†’    pub label: String,
393â†’    /// Confidence score 0.0â€“1.0
394â†’    pub confidence: f64,
395â†’}
396â†’
397â†’/// Classify whether a thrown error is a deliberate validation rejection or an
398â†’/// accidental runtime failure by examining the branch path immediately before the error.
399â†’///
400â†’/// Pattern: a guard branch taken=true followed immediately by the error (no intervening
401â†’/// branches) suggests intentional input rejection. Errors without a preceding guard
402â†’/// or deep in the branch path are more likely accidental.
403â†’pub fn classify_error_intent(result: &crate::protocol::ExecuteResult) -> Option<ErrorIntentLabel> {
404â†’    let error = result.thrown_error.as_ref()?;
405â†’
406â†’    // If the frontend already classified this as infrastructure, trust it
407â†’    if error.error_category.as_deref() == Some("infrastructure") {
408â†’        return Some(ErrorIntentLabel {
409â†’            label: "likely_runtime".into(),
410â†’            confidence: 0.9,
411â†’        });
412â†’    }
413â†’
414â†’    let branch_path = &result.branch_path;
415â†’    if branch_path.is_empty() {
416â†’        // No branch data â€” can't infer intent
417â†’        return Some(ErrorIntentLabel {
418â†’            label: "unknown".into(),
419â†’            confidence: 0.0,
420â†’        });
421â†’    }
422â†’
423â†’    // Check the last branch before the error
424â†’    let last_branch = branch_path.last().unwrap();
425â†’
426â†’    // Guard pattern: last branch taken=true, suggesting an if-guard that led to a throw.
427â†’    // Shallow depth (few branches) + guard = likely validation.
428â†’    if last_branch.taken && branch_path.len() <= 3 {
429â†’        return Some(ErrorIntentLabel {
430â†’            label: "likely_validation".into(),
431â†’            confidence: 0.7,
432â†’        });
433â†’    }
434â†’
435â†’    // Deep branch path with error = likely accidental runtime failure
436â†’    if branch_path.len() > 5 {
437â†’        return Some(ErrorIntentLabel {
438â†’            label: "likely_runtime".into(),
439â†’            confidence: 0.6,
440â†’        });
441â†’    }
442â†’
443â†’    // Frontend-level classification can help disambiguate
444â†’    if error.error_category.as_deref() == Some("validation") {
445â†’        return Some(ErrorIntentLabel {
446â†’            label: "likely_validation".into(),
447â†’            confidence: 0.8,
448â†’        });
449â†’    }
450â†’    if error.error_category.as_deref() == Some("runtime") {
451â†’        return Some(ErrorIntentLabel {
452â†’            label: "likely_runtime".into(),
453â†’            confidence: 0.7,
454â†’        });
455â†’    }
456â†’
457â†’    Some(ErrorIntentLabel {
458â†’        label: "unknown".into(),
459â†’        confidence: 0.3,
460â†’    })
461â†’}
