515â†’/// Explore a single function by generating random inputs and executing them.
516â†’pub async fn explore_function(
517â†’    frontend: &mut Frontend,
518â†’    analysis: &FunctionAnalysis,
519â†’    config: &ExploreConfig,
520â†’) -> Result<ObservationOutput, ExploreError> {
521â†’    let instrument_response = frontend
522â†’        .send(ProtoCommand::Instrument {
523â†’            file: config.file.clone(),
524â†’            function: analysis.name.clone(),
525â†’            mocks: config.mocks.clone(),
526â†’            project_root: config.project_root.clone(),
527â†’        })
528â†’        .await?;
529â†’
530â†’    let instrumentable_line_count = match instrument_response.result {
531â†’        ResponseResult::Instrument { instrumented, instrumentable_line_count, .. } => {
532â†’            if !instrumented {
533â†’                return Err(ExploreError::UnexpectedResponse(
534â†’                    "instrumentation returned instrumented=false".to_string(),
535â†’                ));
536â†’            }
537â†’            instrumentable_line_count
538â†’        }
539â†’        ResponseResult::Error { code, message, .. } => {
540â†’            return Err(ExploreError::UnexpectedResponse(format!(
541â†’                "instrument error ({code:?}): {message}"
542â†’            )));
543â†’        }
544â†’        other => {
545â†’            return Err(ExploreError::UnexpectedResponse(format!(
546â†’                "expected Instrument response, got {other:?}"
547â†’            )));
548â†’        }
549â†’    };
550â†’
551â†’    let mut rng = match config.seed {
552â†’        Some(seed) => StdRng::seed_from_u64(seed),
553â†’        None => StdRng::from_os_rng(),
554â†’    };
555â†’
556â†’    // --- Setup lifecycle ---
557â†’    let has_setup =
558â†’        config.setup_file.is_some() && frontend_supports(&config.capabilities, "setup");
559â†’    let per_function_setup = has_setup && config.setup_mode == SetupMode::PerFunction;
560â†’    let per_execution_setup = has_setup && config.setup_mode == SetupMode::PerExecution;
561â†’
562â†’    let mut setup_context: Option<serde_json::Value> = None;
563â†’
564â†’    if per_function_setup
565â†’        && let Some(ref setup_file) = config.setup_file
566â†’    {
567â†’        setup_context =
568â†’            send_setup(frontend, setup_file, &analysis.name, config.setup_mode, config.project_root.clone()).await?;
569â†’    }
570â†’
571â†’    // --- Generator prefetch ---
572â†’    let has_generators = config
573â†’        .value_sources
574â†’        .iter()
575â†’        .any(|s| matches!(s, ValueSource::CustomGenerator { .. }));
576â†’    let use_generators = has_generators && frontend_supports(&config.capabilities, "generate");
