 28â†’/// Run the Analyze stage on an observation result.
 29â†’///
 30â†’/// Takes the raw exploration output and the static function analysis,
 31â†’/// then produces equivalence classes, a behavior map, and coverage metrics.
 32â†’pub fn analyze(observe: &ObservationOutput, analysis: &FunctionAnalysis) -> AnalyzeOutput {
 33â†’    // Build equivalence classes from raw results.
 34â†’    let eq_classes = equivalence::group_into_classes(&observe.raw_results);
 35â†’
 36â†’    // Build execution records for BehaviorMap construction.
 37â†’    let records: Vec<ExecutionRecord> = observe
 38â†’        .raw_results
 39â†’        .iter()
 40â†’        .map(|(inputs, result)| execution_record_from_result(&observe.function_name, inputs, result))
 41â†’        .collect();
 42â†’
 43â†’    let mut behavior_map = BehaviorMap::from_records(&observe.function_name, &records);
 44â†’    behavior_map.nondeterministic_fields = observe.nondeterministic_fields.clone();
 45â†’
 46â†’    // Deduplicate constraints by branch_id so each branch contributes exactly one classification.
 47â†’    let unique_constraints: HashMap<u32, SymConstraint> = observe
 48â†’        .raw_results
 49â†’        .iter()
 50â†’        .flat_map(|(_, result)| {
 51â†’            result
 52â†’                .branch_path
 53â†’                .iter()
 54â†’                .map(|d| (d.branch_id, d.constraint.clone()))
 55â†’        })
 56â†’        .collect();
 57â†’    let all_constraints: Vec<SymConstraint> = unique_constraints.into_values().collect();
 58â†’
 59â†’    let coverage_metrics = CoverageMetrics::from_exploration(
 60â†’        analysis.branches.len(),
 61â†’        &observe.discoveries,
 62â†’        &all_constraints,
 63â†’    );
 64â†’
 65â†’    AnalyzeOutput {
 66â†’        eq_classes,
 67â†’        behavior_map,
 68â†’        coverage_metrics,
 69â†’    }
 70â†’}
