 83â†’    ExecutionRecord {
 84â†’        function_id: function_id.to_string(),
 85â†’        input_hash,
 86â†’        parameters: inputs.to_vec(),
 87â†’        branch_path: result.branch_path.clone(),
 88â†’        scope_events: result.scope_events.clone(),
 89â†’        lines_executed: result.lines_executed.clone(),
 90â†’        calls_to_external: result.calls_to_external.clone(),
 91â†’        path_constraints: result.path_constraints.clone(),
 92â†’        return_value: result.return_value.clone(),
