 94â†’        side_effects: result.side_effects.clone(),
 95â†’        wall_time_ms: result.performance.wall_time_ms,
 96â†’        cpu_time_us: result.performance.cpu_time_us,
 97â†’        heap_used_bytes: result.performance.heap_used_bytes,
 98â†’        heap_allocated_bytes: result.performance.heap_allocated_bytes,
 99â†’        timestamp: String::new(),
