    // -- Scope-aware path_hash tests --

    use crate::execution_record::{ScopeEvent, TraceEvent};

    /// Helper: LoopBuckets::none() for backward-compat tests.
    fn no_buckets() -> LoopBuckets {
        LoopBuckets::none()
